1	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
2	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
3	import { Firmware } from '@/app/api/lib/models/firmware';
4	import { generateMongoId } from '@/lib/utils/id';
5	import { getClientIP } from '@/lib/utils/ipAddress';
6	import type { FirmwareDocument } from '@/shared/types';
7	import { GridFSBucket, type Db } from 'mongodb';
8	import { NextRequest, NextResponse } from 'next/server';
9	import { Readable } from 'stream';
10	
11	import {
12	  logRouteFetch,
13	  logRouteCreate,
14	  logRouteError,
15	  extractUserFromRequest,
16	} from '@/app/api/lib/utils/routeLogger';
17	
18	/**
19	 * Main GET handler for fetching firmwares
20	 *
21	 * @param {boolean} includeDeleted - Whether to include archived firmware records
22	 */
23	export async function GET(request: NextRequest) {
24	  return withApiAuth(request, async () => {
25	    const startTime = Date.now();
26	    const functionName = 'GET /api/firmwares';
27	    const user = extractUserFromRequest(request);
28	    try {
29	      // ============================================================================
30	      // STEP 1: Parse query parameters
31	      // ============================================================================
32	      const { searchParams } = new URL(request.url);
33	      const includeDeleted = searchParams.get('includeDeleted') === 'true';
34	
35	      const query = includeDeleted
36	        ? {}
37	        : {
38	            $or: [
39	              { deletedAt: null },
40	              { deletedAt: { $lt: new Date('2025-01-01') } },
41	            ],
42	          };
43	
44	      // ============================================================================
45	      // STEP 2: Fetch firmwares
46	      // ============================================================================
47	      const firmwares = await Firmware.find(query)
48	        .sort({ createdAt: -1 })
49	        .lean<FirmwareDocument[]>();
50	      // ============================================================================
51	      // STEP 3: Return success response
52	      // ============================================================================
53	      const duration = Date.now() - startTime;
54	      logRouteFetch(
55	        functionName,
56	        'GET',
57	        '/api/firmwares',
58	        firmwares.length,
59	        user,
60	        duration
61	      );
62	      return NextResponse.json(firmwares);
63	    } catch (error) {
64	      const errorMessage =
65	        error instanceof Error ? error.message : 'Failed to fetch firmwares';
66	      logRouteError(functionName, 'GET', '/api/firmwares', errorMessage, user);
67	      return NextResponse.json(
68	        { error: 'Failed to fetch firmwares' },
69	        { status: 500 }
70	      );
71	    }
72	  });
73	}
74	
75	/**
76	 * POST /api/firmwares
77	 *
78	 * @body {FormData} product - Product name/identifier (REQUIRED)
79	 * @body {FormData} version - Firmware version string (REQUIRED)
80	 * @body {FormData} versionDetails - Description of version changes
81	 * @body {FormData} file - Binary firmware file (.bin only) (REQUIRED)
82	 */
83	export async function POST(request: NextRequest) {
84	  return withApiAuth(request, async ({ user: currentUser, db }) => {
85	    const startTime = Date.now();
86	    const functionName = 'POST /api/firmwares';
87	    const user = extractUserFromRequest(request);
88	    try {
89	      // ============================================================================
90	      // STEP 1: Connect to database and bucket
91	      // ============================================================================
92	      if (!db) throw new Error('Database connection failed');
93	      const bucket = new GridFSBucket(db as unknown as Db, {
94	        bucketName: 'firmwares',
95	      });
96	
97	      // ============================================================================
98	      // STEP 2: Parse form data and validate
99	      // ============================================================================
100	      const formData = await request.formData();
101	      const product = formData.get('product') as string;
102	      const version = formData.get('version') as string;
103	      const versionDetails = formData.get('versionDetails') as string;
104	      const file = formData.get('file') as File;
105	
106	      if (!product || !version || !file) {
107	        return NextResponse.json(
108	          { error: 'Product, version, and file are required' },
109	          { status: 400 }
110	        );
111	      }
112	
113	      if (!file.name.endsWith('.bin')) {
114	        return NextResponse.json(
115	          { error: 'Only .bin files are allowed' },
116	          { status: 400 }
117	        );
118	      }
119	
120	      // ============================================================================
121	      // STEP 3: Prepare file for upload
122	      // ============================================================================
123	      const arrayBuffer = await file.arrayBuffer();
124	      const buffer = Buffer.from(arrayBuffer);
125	      const stream = Readable.from(buffer);
126	
127	      // ============================================================================
128	      // STEP 4: Upload file to GridFS
129	      // ============================================================================
130	      const uploadStream = bucket.openUploadStream(file.name, {
131	        metadata: {
132	          originalName: file.name,
133	          mimeType: file.type,
134	          size: file.size,
135	          uploadedAt: new Date(),
136	        },
137	      });
138	
139	      const fileId = uploadStream.id;
140	      await new Promise((resolve, reject) => {
141	        stream.pipe(uploadStream).on('error', reject).on('finish', resolve);
142	      });
143	
144	      // ============================================================================
145	      // STEP 5: Create firmware entry
146	      // ============================================================================
147	      const firmwareId = await generateMongoId();
148	      const firmware = new Firmware({
149	        _id: firmwareId,
150	        product,
151	        version,
152	        versionDetails: versionDetails || '',
153	        fileId,
154	        fileName: file.name,
155	        fileSize: file.size,
156	        deletedAt: new Date(-1),
157	        releaseDate: new Date(),
158	        description: versionDetails || '',
159	        downloadUrl: '',
160	        checksum: '',
161	      });
162	
163	      await firmware.save();
164	
165	      const duration = Date.now() - startTime;
166	      logRouteCreate(functionName, 'POST', '/api/firmwares', 1, user, duration);
167	
168	      // ============================================================================
169	      // STEP 6: Log activity
170	      // ============================================================================
171	      if (currentUser && currentUser.emailAddress) {
172	        await logActivity({
173	          action: 'CREATE',
174	          details: `Uploaded new firmware "${product} v${version}" (${file.name})`,
175	          ipAddress: getClientIP(request) || undefined,
176	          userId: currentUser._id,
177	          username: currentUser.username || currentUser.emailAddress,
178	
179	          metadata: {
180	            resource: 'Firmware',
181	            resourceId: firmwareId,
182	            resourceName: `${product} v${version}`,
183	            changes: [
184	              { field: 'product', oldValue: null, newValue: product },
185	              { field: 'version', oldValue: null, newValue: version },
186	              { field: 'fileName', oldValue: null, newValue: file.name },
187	            ],
188	          },
189	        });
190	      }
191	
192	      // ============================================================================
193	      // STEP 7: Return success response
194	      // ============================================================================
195	      return NextResponse.json(firmware, { status: 201 });
196	    } catch (error) {
197	      const errorMessage =
198	        error instanceof Error ? error.message : 'Failed to upload firmware';
199	      logRouteError(functionName, 'POST', '/api/firmwares', errorMessage, user);
200	      return NextResponse.json(
201	        { error: 'Failed to upload firmware' },
202	        { status: 500 }
203	      );
204	    }
205	  });
206	}
