1	/**
2	 * Firmware by ID API Route
3	 *
4	 * This route handles operations for a specific firmware identified by ID.
5	 * It supports:
6	 * - DELETE: Soft deleting a firmware
7	 *
8	 * @module app/api/firmwares/[id]/route
9	 */
10	
11	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
12	import {
13	  downloadFirmwareFromGridFS,
14	  findFirmwareById,
15	} from '@/app/api/lib/helpers/firmware';
16	import { getUserFromServer } from '@/app/api/lib/helpers/users';
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import { Firmware } from '@/app/api/lib/models/firmware';
19	import { getClientIP } from '@/lib/utils/ipAddress';
20	import {
21	  logRouteFetch,
22	  logRouteDelete,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	/**
29	 * GET /api/firmwares/[id]
30	 *
31	 * Downloads the raw firmware binary for a given firmware document ID. Called
32	 * when a client needs to retrieve the file directly by its database record ID.
33	 *
34	 * URL params:
35	 * @param id {string} Required (path). The MongoDB ID of the Firmware document to download.
36	 */
37	export async function GET(request: NextRequest) {
38	  const startTime = Date.now();
39	  const functionName = 'GET /api/firmwares/[id]';
40	  const user = extractUserFromRequest(request);
41	  const { pathname } = request.nextUrl;
42	  const id = pathname.split('/').pop();
43	
44	  if (!id) {
45	    return NextResponse.json(
46	      { error: 'Firmware ID is required' },
47	      { status: 400 }
48	    );
49	  }
50	
51	  try {
52	    const firmware = await findFirmwareById(id);
53	    if (!firmware) {
54	      return NextResponse.json(
55	        { error: 'Firmware not found' },
56	        { status: 404 }
57	      );
58	    }
59	
60	    const buffer = await downloadFirmwareFromGridFS(firmware.fileId);
61	
62	    const duration = Date.now() - startTime;
63	    logRouteFetch(
64	      functionName,
65	      'GET',
66	      '/api/firmwares/[id]',
67	      1,
68	      user,
69	      duration
70	    );
71	
72	    return new NextResponse(buffer as unknown as BodyInit, {
73	      status: 200,
74	      headers: {
75	        'Content-Type': 'application/octet-stream',
76	        'Content-Disposition': `attachment; filename="${firmware.fileName}"`,
77	        'Content-Length': buffer.length.toString(),
78	      },
79	    });
80	  } catch (error) {
81	    const errorMessage =
82	      error instanceof Error ? error.message : 'Failed to download firmware';
83	    logRouteError(
84	      functionName,
85	      'GET',
86	      '/api/firmwares/[id]',
87	      errorMessage,
88	      user
89	    );
90	    return NextResponse.json({ error: errorMessage }, { status: 500 });
91	  }
92	}
93	
94	/**
95	 * DELETE /api/firmwares/[id]
96	 *
97	 * Soft-deletes a firmware document by setting its `deletedAt` timestamp. Called
98	 * when an operator removes a firmware version from the management panel; the
99	 * binary is retained in GridFS but the record is no longer surfaced in listings.
100	 *
101	 * URL params:
102	 * @param id {string} Required (path). The MongoDB ID of the Firmware document to delete.
103	 */
104	export async function DELETE(request: NextRequest) {
105	  const startTime = Date.now();
106	  const functionName = 'DELETE /api/firmwares/[id]';
107	  const user = extractUserFromRequest(request);
108	  const { pathname } = request.nextUrl;
109	  const id = pathname.split('/').pop();
110	
111	  try {
112	    if (!id) {
113	      return NextResponse.json(
114	        { message: 'Firmware ID is required' },
115	        { status: 400 }
116	      );
117	    }
118	
119	    // ============================================================================
120	    // STEP 2: Connect to database
121	    // ============================================================================
122	    await connectDB();
123	
124	    // ============================================================================
125	    // STEP 3: Find firmware by ID
126	    // ============================================================================
127	    const firmwareToDeleteData = await findFirmwareById(id);
128	    if (!firmwareToDeleteData) {
129	      return NextResponse.json(
130	        { message: 'Firmware not found' },
131	        { status: 404 }
132	      );
133	    }
134	
135	    // Get the full document for logging details
136	    const firmwareToDelete = await Firmware.findOne({ _id: id });
137	
138	    // ============================================================================
139	    // STEP 4: Soft delete firmware
140	    // ============================================================================
141	    const softDeletedFirmware = await Firmware.findOneAndUpdate(
142	      { _id: id },
143	      { deletedAt: new Date() },
144	      { new: true }
145	    );
146	    if (!softDeletedFirmware) {
147	      return NextResponse.json(
148	        { success: false, error: 'Failed to delete firmware' },
149	        { status: 500 }
150	      );
151	    }
152	
153	    const duration = Date.now() - startTime;
154	    logRouteDelete(
155	      functionName,
156	      'DELETE',
157	      '/api/firmwares/[id]',
158	      1,
159	      user,
160	      duration
161	    );
162	
163	    // Log activity
164	    const currentUser = await getUserFromServer();
165	    if (currentUser && currentUser.emailAddress) {
166	      try {
167	        const deleteChanges = [
168	          {
169	            field: 'product',
170	            oldValue: firmwareToDelete.product,
171	            newValue: null,
172	          },
173	          {
174	            field: 'version',
175	            oldValue: firmwareToDelete.version,
176	            newValue: null,
177	          },
178	          {
179	            field: 'versionDetails',
180	            oldValue: firmwareToDelete.versionDetails,
181	            newValue: null,
182	          },
183	          {
184	            field: 'fileName',
185	            oldValue: firmwareToDelete.fileName,
186	            newValue: null,
187	          },
188	          {
189	            field: 'fileSize',
190	            oldValue: firmwareToDelete.fileSize,
191	            newValue: null,
192	          },
193	        ];
194	
195	        await logActivity({
196	          action: 'DELETE',
197	          details: `Deleted firmware "${firmwareToDelete.product} v${firmwareToDelete.version}" (${firmwareToDelete.fileName})`,
198	          ipAddress: getClientIP(request) || undefined,
199	          userAgent: request.headers.get('user-agent') || undefined,
200	          metadata: {
201	            userId: currentUser._id as string,
202	            userEmail: currentUser.emailAddress as string,
203	            userRole: (currentUser.roles as string[])?.[0] || 'user',
204	            resource: 'Firmware',
205	            resourceId: id,
206	            resourceName: `${firmwareToDelete.product} v${firmwareToDelete.version}`,
207	            changes: deleteChanges,
208	          },
209	        });
210	      } catch (logError) {
211	        console.error('Failed to log activity:', logError);
212	      }
213	    }
214	
215	    return NextResponse.json({
216	      message: 'Firmware deleted successfully',
217	    });
218	  } catch (error) {
219	    const errorMessage =
220	      error instanceof Error ? error.message : 'An unknown error occurred';
221	    logRouteError(
222	      functionName,
223	      'DELETE',
224	      '/api/firmwares/[id]',
225	      errorMessage,
226	      user
227	    );
228	    return NextResponse.json(
229	      { message: 'Error deleting firmware', error: errorMessage },
230	      { status: 500 }
231	    );
232	  }
233	}
