1	/**
2	 * Firmwares Migrate API Route
3	 *
4	 * This route handles firmware schema migration operations.
5	 * It supports:
6	 * - GET: Checking if migration is needed
7	 * - POST: Running the migration for existing firmware records
8	 * - Useful for updating firmware records to match new schema requirements
9	 *
10	 * @module app/api/firmwares/migrate/route
11	 * @features Schema Migration, Data Migration, Firmware Management
12	 */
13	
14	import {
15	  migrateFirmwareSchema,
16	  checkMigrationNeeded,
17	} from '@/lib/utils/firmwareMigration';
18	import {
19	  logRouteFetch,
20	  logRouteCreate,
21	  logRouteError,
22	  extractUserFromRequest,
23	} from '@/app/api/lib/utils/routeLogger';
24	import { NextRequest, NextResponse } from 'next/server';
25	
26	/**
27	 * Main POST handler for running firmware migration
28	 *
29	 * Flow:
30	 * 1. Check if migration is needed
31	 * 2. Run migration if needed
32	 * 3. Return migration result
33	 */
34	export async function POST(request: NextRequest) {
35	  const startTime = Date.now();
36	  const functionName = 'POST /api/firmwares/migrate';
37	  const user = extractUserFromRequest(request);
38	
39	  try {
40	    // ============================================================================
41	    // STEP 1: Check if migration is needed
42	    // ============================================================================
43	    const needsMigration = await checkMigrationNeeded();
44	
45	    if (!needsMigration) {
46	      const duration = Date.now() - startTime;
47	      logRouteFetch(
48	        functionName,
49	        'POST',
50	        '/api/firmwares/migrate',
51	        0,
52	        user,
53	        duration
54	      );
55	      return NextResponse.json(
56	        {
57	          message: 'No migration needed - all firmware records are up to date',
58	        },
59	        { status: 200 }
60	      );
61	    }
62	
63	    // ============================================================================
64	    // STEP 2: Run migration if needed
65	    // ============================================================================
66	    await migrateFirmwareSchema();
67	
68	    // ============================================================================
69	    // STEP 3: Return migration result
70	    // ============================================================================
71	    const duration = Date.now() - startTime;
72	    logRouteCreate(
73	      functionName,
74	      'POST',
75	      '/api/firmwares/migrate',
76	      1,
77	      user,
78	      duration
79	    );
80	
81	    return NextResponse.json(
82	      { message: 'Firmware migration completed successfully' },
83	      { status: 200 }
84	    );
85	  } catch (error: unknown) {
86	    const errorMessage =
87	      error instanceof Error ? error.message : 'Internal server error';
88	    logRouteError(
89	      functionName,
90	      'POST',
91	      '/api/firmwares/migrate',
92	      errorMessage,
93	      user
94	    );
95	    return NextResponse.json(
96	      { error: 'Failed to migrate firmware records' },
97	      { status: 500 }
98	    );
99	  }
100	}
101	
102	/**
103	 * Main GET handler for checking migration status
104	 *
105	 * Flow:
106	 * 1. Check if migration is needed
107	 * 2. Return migration status
108	 */
109	export async function GET(request: NextRequest) {
110	  const startTime = Date.now();
111	  const functionName = 'GET /api/firmwares/migrate';
112	  const user = extractUserFromRequest(request);
113	
114	  try {
115	    // ============================================================================
116	    // STEP 1: Check if migration is needed
117	    // ============================================================================
118	    const needsMigration = await checkMigrationNeeded();
119	
120	    // ============================================================================
121	    // STEP 2: Return migration status
122	    // ============================================================================
123	    const duration = Date.now() - startTime;
124	    logRouteFetch(
125	      functionName,
126	      'GET',
127	      '/api/firmwares/migrate',
128	      1,
129	      user,
130	      duration
131	    );
132	
133	    return NextResponse.json(
134	      {
135	        needsMigration,
136	        message: needsMigration
