143	    const errorMessage =
144	      error instanceof Error ? error.message : 'Internal server error';
145	    logRouteError(
146	      functionName,
147	      'GET',
148	      '/api/firmwares/migrate',
149	      errorMessage,
150	      user
151	    );
152	    return NextResponse.json(
153	      { error: 'Failed to check migration status' },
154	      { status: 500 }
155	    );
156	  }
157	}
