1	/**
2	 * Firmware Download by Version API Route
3	 *
4	 * This route handles downloading firmware files from GridFS by version.
5	 * It supports:
6	 * - Finding firmware by version
7	 * - Downloading firmware file from GridFS
8	 * - Returning file with appropriate headers for SMIB OTA updates
9	 *
10	 * @module app/api/firmwares/download/[version]/route
11	 */
12	
13	import {
14	  downloadFirmwareFromGridFS,
15	  findFirmwareByVersion,
16	} from '@/app/api/lib/helpers/firmware';
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import {
19	  logRouteFetch,
20	  logRouteError,
21	  extractUserFromRequest,
22	} from '@/app/api/lib/utils/routeLogger';
23	import { NextRequest, NextResponse } from 'next/server';
24	
25	/**
26	 * GET /api/firmwares/download/[version]
27	 *
28	 * Streams a firmware binary from GridFS using a version string as the lookup
29	 * key instead of a document ID. Used by SMIB devices during OTA updates to
30	 * fetch a specific firmware version by its human-readable version number;
31	 * response headers disable caching to ensure devices always receive the
32	 * latest binary.
33	 *
34	 * URL params:
35	 * @param version {string} Required (path). The firmware version string to look up (e.g. "1.2.3").
36	 */
37	export async function GET(request: NextRequest) {
38	  const startTime = Date.now();
39	  const functionName = 'GET /api/firmwares/download/[version]';
40	  const user = extractUserFromRequest(request);
41	  const { pathname } = request.nextUrl;
42	  const version = pathname.split('/').pop();
43	
44	  if (!version) {
45	    return NextResponse.json(
46	      { error: 'Firmware version is required' },
47	      { status: 400 }
48	    );
49	  }
50	
51	  try {
52	    // ============================================================================
53	    // STEP 1: Connect to database
54	    // ============================================================================
55	    await connectDB();
56	
57	    // ============================================================================
58	    // STEP 2: Find firmware document by version
59	    // ============================================================================
60	    const firmware = await findFirmwareByVersion(version);
61	    if (!firmware) {
62	      return NextResponse.json(
63	        { error: `Firmware version ${version} not found` },
64	        { status: 404 }
65	      );
66	    }
67	
68	    // ============================================================================
69	    // STEP 3: Download firmware file from GridFS
70	    // ============================================================================
71	    const buffer = await downloadFirmwareFromGridFS(firmware.fileId);
72	
73	    // ============================================================================
74	    // STEP 4: Return file with appropriate headers for SMIB OTA
75	    // ============================================================================
76	    const duration = Date.now() - startTime;
77	    logRouteFetch(
78	      functionName,
79	      'GET',
80	      '/api/firmwares/download/[version]',
81	      1,
82	      user,
83	      duration
84	    );
85	    return new NextResponse(buffer as unknown as BodyInit, {
86	      status: 200,
87	      headers: {
88	        'Content-Type': 'application/octet-stream',
89	        'Content-Disposition': `attachment; filename="${firmware.fileName}"`,
90	        'Content-Length': buffer.length.toString(),
91	        'Cache-Control': 'no-cache, no-store, must-revalidate',
92	        Pragma: 'no-cache',
93	        Expires: '0',
94	      },
95	    });
96	  } catch (error) {
97	    const errorMessage =
98	      error instanceof Error ? error.message : 'Failed to download firmware';
99	    logRouteError(
100	      functionName,
101	      'GET',
102	      '/api/firmwares/download/[version]',
103	      errorMessage,
104	      user
105	    );
106	    return NextResponse.json({ error: errorMessage }, { status: 500 });
107	  }
108	}
