1	/**
2	 * Firmware Serve API Route
3	 *
4	 * This route handles serving firmware files from GridFS.
5	 * It supports:
6	 * - Downloading firmware from GridFS to /public/firmwares/
7	 * - Returning static URL for the firmware file
8	 * - Auto-cleaning up files after 30 minutes
9	 *
10	 * @module app/api/firmwares/[id]/serve/route
11	 */
12	
13	import { downloadFirmwareFromGridFS } from '@/app/api/lib/helpers/firmware';
14	import { connectDB } from '@/app/api/lib/middleware/db';
15	import { Firmware } from '@/app/api/lib/models/firmware';
16	import fs from 'fs';
17	import { GridFSBucket } from 'mongodb';
18	import { NextRequest, NextResponse } from 'next/server';
19	import path from 'path';
20	import type { FirmwareDocument } from '@shared/types';
21	import {
22	  logRouteFetch,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	
27	/**
28	 * GET /api/firmwares/[id]/serve
29	 *
30	 * Extracts a firmware binary from GridFS onto disk at `/public/firmwares/` and
31	 * returns a static URL pointing to that file. Called by the OTA update flow
32	 * before broadcasting the download URL to SMIBs via MQTT; the file is
33	 * automatically deleted from disk after 30 minutes.
34	 *
35	 * URL params:
36	 * @param {string} id - Required (path). The MongoDB ID of the Firmware document to serve.
37	 */
38	export async function GET(request: NextRequest) {
39	  const startTime = Date.now();
40	  const functionName = 'GET /api/firmwares/[id]/serve';
41	  const user = extractUserFromRequest(request);
42	  const { pathname } = request.nextUrl;
43	  const id = pathname.split('/').at(-2); // Extract [id] from /api/firmwares/[id]/serve
44	
45	  try {
46	    // ============================================================================
47	    // STEP 1: Connect to database and initialize GridFS bucket
48	    // ============================================================================
49	    const db = await connectDB();
50	    if (!db) {
51	      throw new Error('Database connection failed');
52	    }
53	    // ============================================================================
54	    // STEP 2: Parse and validate request parameters
55	    // ============================================================================
56	
57	    // ============================================================================
58	    // STEP 3: Find firmware document
59	    // ============================================================================
60	    const firmwareDoc = await Firmware.findOne({
61	      _id: id,
62	    }).lean<FirmwareDocument>();
63	    if (!firmwareDoc) {
64	      return NextResponse.json(
65	        { error: 'Firmware not found' },
66	        { status: 404 }
67	      );
68	    }
69	
70	    const firmware = {
71	      fileId: firmwareDoc.fileId as Parameters<
72	        GridFSBucket['openDownloadStream']
73	      >[0],
74	      fileName: firmwareDoc.fileName ?? '',
75	    };
76	
77	    // ============================================================================
78	    // STEP 4: Create /public/firmwares directory if needed
79	    // ============================================================================
80	    const firmwaresDir = path.join(process.cwd(), 'public', 'firmwares');
81	    if (!fs.existsSync(firmwaresDir)) {
82	      fs.mkdirSync(firmwaresDir, { recursive: true });
83	    }
84	
85	    const filePath = path.join(firmwaresDir, firmware.fileName);
86	
87	    // ============================================================================
88	    // STEP 5: Download firmware from GridFS
89	    // ============================================================================
90	    const buffer = await downloadFirmwareFromGridFS(firmware.fileId);
91	
92	    // ============================================================================
93	    // STEP 6: Write file to /public/firmwares/
94	    // ============================================================================
95	    fs.writeFileSync(filePath, buffer);
96	
97	    // ============================================================================
98	    // STEP 7: Schedule auto-cleanup after 30 minutes
99	    // ============================================================================
100	    setTimeout(
101	      () => {
102	        try {
103	          if (fs.existsSync(filePath)) {
104	            fs.unlinkSync(filePath);
105	          }
106	        } catch (cleanupError) {
107	          console.error('Firmware cleanup failed:', cleanupError);
108	        }
109	      },
110	      30 * 60 * 1000
111	    );
112	
113	    // ============================================================================
114	    // STEP 8: Return static URL
115	    // ============================================================================
116	    const duration = Date.now() - startTime;
117	    logRouteFetch(
118	      functionName,
119	      'GET',
120	      `/api/firmwares/${id}/serve`,
121	      1,
122	      user,
123	      duration
124	    );
125	    const staticUrl = `/firmwares/${firmware.fileName}`;
126	
127	    return NextResponse.json({
128	      success: true,
129	      fileName: firmware.fileName,
130	      staticUrl,
131	      size: buffer.length,
132	    });
133	  } catch (error) {
134	    const errorMessage =
135	      error instanceof Error ? error.message : 'Failed to serve firmware';
136	    logRouteError(
137	      functionName,
138	      'GET',
139	      `/api/firmwares/${id}/serve`,
140	      errorMessage,
141	      user
142	    );
143	    return NextResponse.json({ error: errorMessage }, { status: 500 });
144	  }
145	}
