1	/**
2	 * Firmware Download by ID API Route
3	 *
4	 * This route handles downloading firmware files from GridFS by firmware ID.
5	 * It supports:
6	 * - Finding firmware by ID
7	 * - Downloading firmware file from GridFS
8	 * - Returning file with appropriate headers
9	 *
10	 * @module app/api/firmwares/[id]/download/route
11	 */
12	
13	import {
14	  downloadFirmwareFromGridFS,
15	  findFirmwareById,
16	} from '@/app/api/lib/helpers/firmware';
17	import {
18	  logRouteFetch,
19	  logRouteError,
20	  extractUserFromRequest,
21	} from '@/app/api/lib/utils/routeLogger';
22	import { NextRequest, NextResponse } from 'next/server';
23	
24	/**
25	 * GET /api/firmwares/[id]/download
26	 *
27	 * Streams the firmware binary from GridFS as an `application/octet-stream`
28	 * attachment. Called when a user manually triggers a firmware download from
29	 * the firmware management UI.
30	 *
31	 * URL params:
32	 * @param id {string} Required (path). The MongoDB ID of the Firmware document to download.
33	 */
34	export async function GET(request: NextRequest) {
35	  const startTime = Date.now();
36	  const functionName = 'GET /api/firmwares/[id]/download';
37	  const user = extractUserFromRequest(request);
38	  const { pathname } = request.nextUrl;
39	  const id = pathname.split('/').at(-2); // Extract [id] from /api/firmwares/[id]/download
40	
41	  if (!id) {
42	    return NextResponse.json(
43	      { error: 'Firmware ID is required' },
44	      { status: 400 }
45	    );
46	  }
47	
48	  try {
49	    // ============================================================================
50	    // STEP 2: Find firmware document by ID
51	    // ============================================================================
52	    const firmware = await findFirmwareById(id);
53	    if (!firmware) {
54	      return NextResponse.json(
55	        { error: 'Firmware not found' },
56	        { status: 404 }
57	      );
58	    }
59	
60	    // ============================================================================
61	    // STEP 3: Download firmware file from GridFS
62	    // ============================================================================
63	    const buffer = await downloadFirmwareFromGridFS(firmware.fileId);
64	
65	    // ============================================================================
66	    // STEP 4: Return file with appropriate headers
67	    // ============================================================================
68	    const duration = Date.now() - startTime;
69	    logRouteFetch(
70	      functionName,
71	      'GET',
72	      `/api/firmwares/${id}/download`,
73	      1,
74	      user,
75	      duration
76	    );
77	    return new NextResponse(buffer as unknown as BodyInit, {
78	      status: 200,
79	      headers: {
80	        'Content-Type': 'application/octet-stream',
81	        'Content-Disposition': `attachment; filename="${firmware.fileName}"`,
82	        'Content-Length': buffer.length.toString(),
83	      },
84	    });
85	  } catch (error) {
86	    const errorMessage =
87	      error instanceof Error ? error.message : 'Failed to download firmware';
88	    logRouteError(
89	      functionName,
90	      'GET',
91	      `/api/firmwares/${id}/download`,
92	      errorMessage,
93	      user
94	    );
95	    return NextResponse.json({ error: errorMessage }, { status: 500 });
96	  }
97	}
