1	/**
2	 * DownloadFirmwareModal Component
3	 * Confirmation modal for downloading a firmware file with GSAP animations.
4	 */
5	'use client';
6	
7	import { Button } from '@/components/shared/ui/button';
8	import { useFirmwareActionsStore } from '@/lib/store/firmwareActionsStore';
9	import { Cross1Icon, DownloadIcon } from '@radix-ui/react-icons';
10	import axios from 'axios';
11	import { gsap } from 'gsap';
12	import { useEffect, useRef, useState } from 'react';
13	
14	export const DownloadFirmwareModal = ({
15	  onDownloadComplete,
16	}: {
17	  onDownloadComplete: () => void;
18	}) => {
19	  // ============================================================================
20	  // State & Hooks
21	  // ============================================================================
22	
23	  const { isDownloadModalOpen, selectedFirmware, closeDownloadModal } =
24	    useFirmwareActionsStore();
25	  const modalRef = useRef<HTMLDivElement>(null);
26	  const backdropRef = useRef<HTMLDivElement>(null);
27	  const [loading, setLoading] = useState(false);
28	
29	  // ============================================================================
30	  // Effects
31	  // ============================================================================
32	
33	  useEffect(() => {
34	    if (isDownloadModalOpen) {
35	      gsap.to(modalRef.current, {
36	        y: 0,
37	        opacity: 1,
38	        duration: 0.3,
39	        ease: 'power2.out',
40	      });
41	      gsap.to(backdropRef.current, {
42	        opacity: 1,
43	        duration: 0.2,
44	        ease: 'power2.out',
45	      });
46	    }
47	  }, [isDownloadModalOpen]);
48	
49	  // ============================================================================
50	  // Handlers
51	  // ============================================================================
52	
53	  const handleClose = () => {
54	    gsap.to(modalRef.current, {
55	      y: -20,
56	      opacity: 0,
57	      duration: 0.3,
58	      ease: 'power2.in',
59	    });
60	    gsap.to(backdropRef.current, {
61	      opacity: 0,
62	      duration: 0.2,
63	      ease: 'power2.in',
64	      onComplete: closeDownloadModal,
65	    });
66	  };
67	
68	  const handleDownload = async () => {
69	    if (!selectedFirmware) return;
70	    setLoading(true);
71	    try {
72	      const response = await axios.get(
73	        `/api/firmwares/${selectedFirmware._id}`,
74	        {
75	          responseType: 'blob',
76	          withCredentials: true,
77	        }
78	      );
79	      const blob = response.data;
80	      const url = window.URL.createObjectURL(blob);
81	      const a = document.createElement('a');
82	      a.href = url;
83	      a.download = selectedFirmware.fileName;
84	      document.body.appendChild(a);
85	      a.click();
86	      window.URL.revokeObjectURL(url);
87	      document.body.removeChild(a);
88	      onDownloadComplete();
