93	      setLoading(false);
94	      handleClose();
95	    }
96	  };
97	
98	  // ============================================================================
99	  // Render
100	  // ============================================================================
101	
102	  // Guard: modal not open or no firmware selected
103	  if (!isDownloadModalOpen || !selectedFirmware) return null;
104	
105	  return (
106	    <div className="fixed inset-0 z-50 flex items-center justify-center">
107	      <div
108	        ref={backdropRef}
109	        className="absolute inset-0 bg-black/50 opacity-0"
110	        onClick={handleClose}
111	      />
112	      <div
113	        ref={modalRef}
114	        className="w-full max-w-sm rounded-lg bg-container opacity-0 shadow-xl"
115	        style={{ transform: 'translateY(-20px)' }}
116	      >
117	        <div className="flex items-center justify-between border-b border-border p-4">
118	          <h2 className="text-xl font-bold text-buttonActive">
119	            Download Confirmation
120	          </h2>
121	          <Button
122	            variant="ghost"
123	            size="icon"
124	            onClick={handleClose}
125	            className="text-grayHighlight hover:bg-buttonInactive/10"
126	          >
127	            <Cross1Icon className="h-5 w-5" />
128	          </Button>
129	        </div>
130	        <div className="p-6 text-center">
131	          <div className="mb-4 flex justify-center">
132	            <DownloadIcon className="h-16 w-16 text-green-500" />
133	          </div>
134	          <p className="mb-2 text-lg font-semibold text-grayHighlight">
135	            Do you want to download this firmware?
136	          </p>
137	          <p className="text-gray-200">
138	            Product:{' '}
139	            <span className="font-bold text-buttonActive">
140	              {selectedFirmware.product}
141	            </span>
142	          </p>
143	          <p className="text-gray-200">
144	            Version:{' '}
145	            <span className="font-bold text-buttonActive">
146	              {selectedFirmware.version}
147	            </span>
148	          </p>
149	          <p className="text-gray-200">
150	            File:{' '}
151	            <span className="font-bold text-buttonActive">
152	              {selectedFirmware.fileName}
153	            </span>
154	          </p>
155	        </div>
156	        <div className="flex justify-center space-x-4 border-t border-border p-4">
157	          <Button
158	            onClick={handleDownload}
159	            className="bg-green-600 text-white hover:bg-green-700"
160	            disabled={loading}
161	          >
162	            {loading ? 'Downloading...' : 'Download'}
163	          </Button>
164	          <Button
165	            onClick={handleClose}
166	            variant="outline"
167	            className="bg-buttonInactive text-primary-foreground hover:bg-buttonInactive/90"
