1	/**
2	 * UploadSmibDataModal Component
3	 * Modal for uploading a CSV file containing SMIB device data.
4	 */
5	import { useState, useRef } from 'react';
6	
7	import { ChangeEvent, FC } from 'react';
8	import axios from 'axios';
9	import {
10	  Dialog,
11	  DialogContent,
12	  DialogHeader,
13	  DialogTitle,
14	  DialogFooter,
15	  DialogClose,
16	} from '@/components/shared/ui/dialog';
17	import { Button } from '@/components/shared/ui/button';
18	import { Textarea } from '@/components/shared/ui/textarea';
19	import { UploadIcon } from '@radix-ui/react-icons'; // Using UploadIcon for the button
20	import type { UploadSmibDataModalProps } from '@/lib/types/components';
21	import { useUserStore } from '@/lib/store/userStore';
22	
23	const UploadSmibDataModal: FC<UploadSmibDataModalProps> = ({
24	  isOpen,
25	  onClose,
26	  onRefresh,
27	}) => {
28	  // ============================================================================
29	  // State & Hooks
30	  // ============================================================================
31	
32	  const { user } = useUserStore();
33	  const [selectedFile, setSelectedFile] = useState<File | null>(null);
34	  const [comments, setComments] = useState('');
35	  const fileInputRef = useRef<HTMLInputElement>(null);
36	
37	  // ============================================================================
38	  // Computed
39	  // ============================================================================
40	
41	  // Helper function to get proper user display name for activity logging
42	  const getUserDisplayName = () => {
43	    if (!user) return 'Unknown User';
44	
45	    // Check if user has profile with firstName and lastName
46	    if (user.profile?.firstName && user.profile?.lastName) {
47	      return `${user.profile.firstName} ${user.profile.lastName}`;
48	    }
49	
50	    // If only firstName exists, use it
51	    if (user.profile?.firstName && !user.profile?.lastName) {
52	      return user.profile.firstName;
53	    }
54	
55	    // If only lastName exists, use it
56	    if (!user.profile?.firstName && user.profile?.lastName) {
57	      return user.profile.lastName;
58	    }
59	
60	    // If neither firstName nor lastName exist, use username
61	    if (user.username && user.username.trim() !== '') {
62	      return user.username;
63	    }
64	
65	    // If username doesn't exist or is blank, use email
66	    if (user.emailAddress && user.emailAddress.trim() !== '') {
67	      return user.emailAddress;
68	    }
69	
70	    // Fallback
71	    return 'Unknown User';
72	  };
73	
74	  // ============================================================================
75	  // Handlers
76	  // ============================================================================
77	
78	  // Activity logging is now handled via API calls
79	  const logActivity = async (
80	    action: string,
81	    resource: string,
82	    resourceId: string,
83	    resourceName: string,
84	    details: string,
85	    previousData?: Record<string, unknown> | null,
86	    newData?: Record<string, unknown> | null
87	  ) => {
88	    try {
89	      const response = await fetch('/api/activity-logs', {
90	        method: 'POST',
91	        headers: {
92	          'Content-Type': 'application/json',
93	        },
94	        body: JSON.stringify({
95	          action,
96	          resource,
97	          resourceId,
98	          resourceName,
99	          details,
100	          userId: user?._id || 'unknown',
101	          username: getUserDisplayName(),
102	          userRole: 'user',
103	          previousData: previousData || null,
104	          newData: newData || null,
105	          changes: [], // Will be calculated by the API
106	        }),
107	      });
108	
109	      if (!response.ok) {
110	        console.error('Failed to log activity:', response.statusText);
111	      }
112	    } catch (error) {
113	      console.error('Error logging activity:', error);
114	    }
115	  };
116	
117	  const handleFileChange = (event: ChangeEvent<HTMLInputElement>) => {
118	    if (event.target.files && event.target.files[0]) {
119	      setSelectedFile(event.target.files[0]);
120	    }
121	  };
122	
123	  const handleChooseFileClick = () => {
124	    fileInputRef.current?.click();
125	  };
126	
127	  const handleUpload = async () => {
128	    if (!selectedFile) return;
129	
130	    try {
131	      const formData = new FormData();
132	      formData.append('file', selectedFile);
133	      formData.append('comments', comments);
134	
135	      const response = await axios.post(
136	        '/api/firmware/upload-smib-data',
137	        formData
138	      );
139	
140	      // Log the SMIB data upload activity
141	      await logActivity(
142	        'create',
143	        'firmware',
144	        response.data?.id || 'unknown',
145	        `SMIB Data Upload: ${selectedFile.name}`,
146	        `Uploaded SMIB data file: ${selectedFile.name} (${(
147	          selectedFile.size / 1024
148	        ).toFixed(2)} KB)`,
149	        null, // No previous data for creation
150	        response.data // New data
151	      );
152	
153	      // Refresh the parent page data after successful upload
154	      if (onRefresh) {
155	        onRefresh();
156	      }
157	
158	      // Close modal and clear form on success
159	      onClose();
160	      setSelectedFile(null);
161	      setComments('');
162	
163	      // Optional: Show success message
164	      if (typeof window !== 'undefined') {
165	        alert('SMIB data uploaded successfully!');
166	      }
167	    } catch (error) {
168	      console.error('Upload error:', error);
169	      // Optional: Show error message
170	      if (typeof window !== 'undefined') {
171	        alert('Upload failed. Please try again.');
172	      }
173	    }
174	  };
175	
176	  const clearForm = () => {
177	    setSelectedFile(null);
178	    setComments('');
179	  };
180	
181	  const handleModalClose = () => {
182	    clearForm();
183	    onClose();
184	  };
185	
186	  // ============================================================================
187	  // Render
188	  // ============================================================================
189	
190	  return (
191	    <Dialog open={isOpen} onOpenChange={handleModalClose}>
192	      <DialogContent className="max-w-lg overflow-hidden bg-white p-0">
193	        <DialogHeader className="border-b border-gray-200 p-6">
194	          <DialogTitle className="text-2xl font-bold text-gray-800">
195	            Upload CSV with SMIBs data
196	          </DialogTitle>
197	        </DialogHeader>
198	
199	        <div className="flex flex-col gap-6 p-6">
200	          <div>
201	            <Button
202	              variant="outline"
203	              onClick={handleChooseFileClick}
204	              className="w-full justify-start border-gray-300 text-left text-gray-700 hover:bg-gray-100 focus:border-buttonActive focus:ring-buttonActive"
205	            >
206	              <UploadIcon className="mr-2 h-5 w-5 text-gray-600" />
207	              {selectedFile ? selectedFile.name : 'Choose File...'}
208	            </Button>
209	            <input
210	              type="file"
211	              ref={fileInputRef}
212	              onChange={handleFileChange}
213	              className="hidden"
214	              accept=".csv"
215	            />
216	            {selectedFile && (
217	              <p className="mt-1 text-xs text-gray-500">
218	                Type: {selectedFile.type}, Size:{' '}
219	                {(selectedFile.size / 1024).toFixed(2)} KB
220	              </p>
221	            )}
222	          </div>
223	
224	          <div>
225	            <label
226	              htmlFor="techCommentsUpload"
227	              className="mb-1 block text-sm font-medium text-gray-700"
228	            >
229	              Technician Comments
230	            </label>
231	            <Textarea
232	              id="techCommentsUpload"
233	              placeholder="Add any comments related to this upload..."
234	              value={comments}
235	              onChange={e => setComments(e.target.value)}
236	              className="min-h-[100px] border-gray-300 placeholder-gray-400 focus:border-buttonActive focus:ring-buttonActive"
237	            />
238	          </div>
239	        </div>
240	
241	        <DialogFooter className="border-t border-gray-200 p-6">
242	          <DialogClose asChild>
243	            <Button
244	              variant="outline"
245	              onClick={handleModalClose}
246	              className="border-gray-300 text-gray-700 hover:bg-gray-100"
247	            >
248	              Cancel
249	            </Button>
250	          </DialogClose>
251	          <Button
252	            onClick={handleUpload}
253	            disabled={!selectedFile}
254	            className="bg-button text-white hover:bg-button/90"
255	          >
256	            Save
257	          </Button>
258	        </DialogFooter>
259	      </DialogContent>
260	    </Dialog>
261	  );
262	};
263	
264	export default UploadSmibDataModal;
