1	/**
2	 * Firmware Helper Functions
3	 *
4	 * This module contains helper functions for firmware API routes.
5	 * It handles GridFS operations, firmware file downloads, and file serving.
6	 *
7	 * @module app/api/lib/helpers/firmware
8	 */
9	
10	import { Firmware } from '@/lib/types/firmware';
11	import { Db, GridFSBucket, ObjectId } from 'mongodb';
12	import { connectDB } from '../middleware/db';
13	import { Firmware as FirmwareModel } from '../models/firmware';
14	
15	/**
16	 * Firmware file data
17	 */
18	export type FirmwareFileData = {
19	  fileId: string | ObjectId;
20	  fileName: string;
21	};
22	
23	/**
24	 * Downloads firmware file from GridFS as buffer
25	 *
26	 * @param fileId - GridFS file ID (as stored in the Firmware document)
27	 * @returns Buffer containing firmware file data
28	 */
29	export async function downloadFirmwareFromGridFS(
30	  fileId: string | ObjectId
31	): Promise<Buffer> {
32	  if (!fileId) {
33	    console.error('[downloadFirmwareFromGridFS] fileId is required');
34	    throw new Error('[downloadFirmwareFromGridFS] fileId is required');
35	  }
36	  const db = await connectDB();
37	  if (!db) {
38	    throw new Error('Database connection failed');
39	  }
40	
41	  const bucket = new GridFSBucket(db as unknown as Db, {
42	    bucketName: 'firmwares',
43	  });
44	
45	  // GridFSBucket.openDownloadStream accepts ObjectId or string.
46	  // Casting to 'any' here only for the driver call to bypass complex internal typing
47	  // if necessary, but we've defined the input type strictly.
48	  const downloadStream = bucket.openDownloadStream(fileId as ObjectId);
49	
50	  const chunks: Buffer[] = [];
51	  try {
52	    for await (const chunk of downloadStream) {
53	      chunks.push(chunk);
54	    }
55	  } catch (err) {
56	    console.error(
57	      '[downloadFirmwareFromGridFS] Error:',
58	      err instanceof Error ? err.message : 'Unknown error'
59	    );
60	    throw err;
61	  }
62	
63	  return Buffer.concat(chunks);
64	}
65	
66	/**
67	 * Finds firmware document by ID
68	 *
69	 * @param firmwareId - Firmware document ID (String)
70	 * @returns Firmware file data or null if not found
71	 */
72	export async function findFirmwareById(
73	  firmwareId: string
74	): Promise<FirmwareFileData | null> {
75	  if (!firmwareId) {
76	    console.error('[findFirmwareById] firmwareId is required');
77	    return null;
78	  }
79	  await connectDB();
80	
81	  // Use .lean<Firmware>() to get a typed object
82	  const firmwareDoc = await FirmwareModel.findOne({
83	    _id: firmwareId,
84	  }).lean<Firmware>();
85	
86	  if (!firmwareDoc) {
87	    return null;
88	  }
89	
90	  return {
91	    fileId: firmwareDoc.fileId,
92	    fileName: firmwareDoc.fileName,
93	  };
94	}
95	
96	/**
97	 * Finds firmware document by version
98	 *
99	 * @param version - Firmware version string
100	 * @returns Firmware file data or null if not found
101	 */
102	export async function findFirmwareByVersion(
103	  version: string
104	): Promise<FirmwareFileData | null> {
105	  if (!version) {
106	    console.error('[findFirmwareByVersion] version is required');
107	    return null;
108	  }
109	  await connectDB();
110	
111	  const firmwareDoc = await FirmwareModel.findOne({
112	    version: version,
113	    $or: [{ deletedAt: null }, { deletedAt: { $lt: new Date('2025-01-01') } }],
114	  }).lean<Firmware>();
115	
116	  if (!firmwareDoc) {
117	    return null;
118	  }
119	
120	  return {
121	    fileId: firmwareDoc.fileId,
122	    fileName: firmwareDoc.fileName,
123	  };
124	}
