  const id = pathname.split('/').at(-2); // Extract [id] from /api/firmwares/[id]/serve

  try {
    // ============================================================================
    // STEP 1: Connect to database and initialize GridFS bucket
    // ============================================================================
    const db = await connectDB();
    if (!db) {
      throw new Error('Database connection failed');
    }
    // ============================================================================
